export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i += 1
      continue
    }
    if (arg.includes('=')) {
      const [key, value] = arg.split('=', 2)
      result[key.slice(2)] = value
      i += 1
      continue
    }
    const key = arg.slice(2)
    if (i + 1 < argv.length && !argv[i + 1].startsWith('--') && !argv[i + 1].includes('=')) {
      result[key] = argv[i + 1]
      i += 2
      continue
    }
    result[key] = true
    i += 1
  }
  return result
}

